arguments.new_str:
using ModelContextProtocol.Server;

var builder = WebApplication.CreateBuilder(args);

builder.Services
    .AddMcpServer(options =>
    {
        options.ServerInfo = new()
        {
            Name = "McpHttpServer",
            Version = "1.0.0"
        };
    })
    .WithHttpTransport()
    .WithTools<AppTools>()
    .WithResources<AppResources>();

var app = builder.Build();

app.MapMcp();

app.Run();

arguments.file_text:
using System.ComponentModel;
using ModelContextProtocol.Server;

[McpServerToolType]
public static class AppTools
{
    [McpServerTool(Name = "echo"), Description("Echoes the input message back.")]
    public static string Echo(string message) => $"Echo: {message}";

    [McpServerTool(Name = "add"), Description("Adds two numbers together.")]
    public static double Add(double a, double b) => a + b;
}

using System.ComponentModel;
using ModelContextProtocol.Server;

[McpServerResourceType]
public static class AppResources
{
    [McpServerResource(UriTemplate = "config://app/settings", Name = "app-settings", MimeType = "application/json"),
     Description("Returns application configuration data.")]
    public static string GetAppSettings()
    {
        var settings = new
        {
            environment = "production",
            version = "1.0.0",
            features = new
            {
                darkMode = true,
                maxUploadSizeMb = 50,
                supportedLanguages = new[] { "en", "es", "fr" }
            }
        };

        return System.Text.Json.JsonSerializer.Serialize(settings,
            new System.Text.Json.JsonSerializerOptions { WriteIndented = true });
    }

    [McpServerResource(UriTemplate = "config://app/status", Name = "app-status", MimeType = "application/json"),
     Description("Returns the current server health status.")]
    public static string GetStatus()
    {
        return System.Text.Json.JsonSerializer.Serialize(new
        {
            status = "healthy",
            uptime = Environment.TickCount64 / 1000,
            timestamp = DateTimeOffset.UtcNow
        }, new System.Text.Json.JsonSerializerOptions { WriteIndented = true });
    }
}

